def same_chars(s0: str, s1: str):
    if len(s0) != len(s1):
        return False

    char_count_s0 = {}
    char_count_s1 = {}

    for char in s0:
        char_count_s0[char] = char_count_s0.get(char, 0) + 1

    for char in s1:
        char_count_s1[char] = char_count_s1.get(char, 0) + 1

    return char_count_s0 == char_count_s1

